2	import { parse } from '../src/parse';
3	import { encode } from '../src/encode';
4	import { walkNodes, type OutlineDoc } from '../src/model';
5	import { indent, outdent, moveDown, moveUp } from '../src/ops';
6	import { applyEdits } from '../src/result';
7	
8	/** Find the node whose first line matches. */
9	function byLine(doc: OutlineDoc, line: string): number {
10	  for (const node of walkNodes(doc)) {
11	    if (node.lines[0] === line) return node.id;
12	  }
13	  throw new Error(`no node with line: ${line}`);
14	}
15	
16	function applyOk(
17	  op: typeof indent,
18	  md: string,
19	  line: string,
20	): { text: string; doc: OutlineDoc } {
21	  const doc = parse(md);
22	  const result = op(doc, byLine(doc, line));
23	  if (!result.ok) throw new Error(`unexpected rejection: ${result.rejection.reason}`);
24	  // The edit list must reproduce the encoding exactly.
25	  const viaEdits = applyEdits(md === '' ? [] : md.split('\n'), result.value.edits).join('\n');
26	  const text = encode(result.value.doc);
27	  expect(viaEdits).toBe(text);
28	  return { text, doc: result.value.doc };
29	}
30	
31	function expectReject(op: typeof indent, md: string, line: string, reason: string): void {
32	  const doc = parse(md);
33	  const result = op(doc, byLine(doc, line));
34	  expect(result.ok).toBe(false);
35	  if (!result.ok) expect(result.rejection.reason).toBe(reason);
36	}
37	
38	describe('heading level ops', () => {
39	  const md = '## Packing\n\nClothes notes.\n\n## Budget\n\nFerry costs seem high.\n\n### Transport\n';
40	
41	  it('demote shifts the whole subtree, content lines untouched', () => {
42	    const { text } = applyOk(indent, md, '## Budget');
43	    expect(text).toBe(
44	      '## Packing\n\nClothes notes.\n\n### Budget\n\nFerry costs seem high.\n\n#### Transport\n',
45	    );
46	  });
47	
48	  it('outdent consumes a level skip before changing hierarchy', () => {
49	    const skip = '# Log\n\n### Monday\n\nNotes.\n';
50	    const first = applyOk(outdent, skip, '### Monday');
51	    expect(first.text).toBe('# Log\n\n## Monday\n\nNotes.\n');
52	    // Still a child of # Log.
53	    expect(first.doc.children[0]!.children.some((n) => n.lines[0] === '## Monday')).toBe(true);
54	    const second = applyOk(outdent, first.text, '## Monday');
55	    expect(second.text).toBe('# Log\n\n# Monday\n\nNotes.\n');
56	    expect(second.doc.children[1]!.lines[0]).toBe('# Monday');
57	  });
58	
59	  it('demote may create a skip (styling-only edit)', () => {
60	    const src = '## Packing\n\nClothes notes.\n\n### Electronics\n\n- chargers\n';
61	    const { text, doc } = applyOk(indent, src, '### Electronics');
62	    expect(text).toBe('## Packing\n\nClothes notes.\n\n#### Electronics\n\n- chargers\n');
63	    const packing = doc.children[0]!;
64	    expect(packing.children.some((n) => n.lines[0] === '#### Electronics')).toBe(true);
65	  });
66	
67	  it('rejects at the bounds', () => {
68	    expectReject(indent, '###### Tiny\n', '###### Tiny', 'at-h6-bound');
69	    expectReject(outdent, '# Top\n', '# Top', 'at-h1-bound');
70	    // Bound applies to the deepest heading in the subtree.
71	    expectReject(indent, '##### Five\n\n###### Six\n', '##### Five', 'at-h6-bound');
72	  });
73	
74	  it('setext headings convert to ATX when the level changes', () => {
