96	    // sibling (a loose list — same tree, minimal edits).
97	    expect(text).toBe('A.\n\n- existing child\n\n- B.\n');
98	    const a = doc.children[0]!;
99	    expect(a.children.map((n) => n.lines[0])).toEqual(['- existing child', '- B.']);
100	  });
101	
102	  it('outdent keeps the subtree attached via the attachment rule', () => {
103	    const src = '# Notes\n\nPara.\n\n- x\n  - y\n';
104	    const { text, doc } = applyOk(outdent, src, '- x');
105	    // No blank between x and its child list needed: a bullet line always
106	    // starts a new block, and the attachment rule claims it as x's child.
107	    expect(text).toBe('# Notes\n\nPara.\n\nx\n- y\n');
108	    const notes = doc.children[0]!;
