  let max = node.kind === 'heading' ? (node.level ?? 1) : 0;
  for (const child of node.children) max = Math.max(max, maxHeadingLevel(child));
  return max;
}

function headingLevelOp(
  doc: OutlineDoc,
  path: readonly number[],
  node: OutlineNode,
  delta: number,
