1	/**
2	 * CM6 adapter for the enforcement funnel (design.md D1/D2/D4/D7): a single
3	 * `EditorState.transactionFilter` that classifies every transaction in an
4	 * outline-mode editor, escalates boundary-crossing selections
5	 * (`selection-only`), and — new in Phase C — hands `boundary-crossing-edit`
6	 * transactions to the pure verdict layer (`src/enforce.ts`), applying its
7	 * `pass`/`rewrite`/`veto` verdict. A companion `EditorView.updateListener`
8	 * (registered alongside the filter, not inside it — filters must stay
9	 * side-effect-free) surfaces the veto rejection cue, the same split
10	 * decorations.ts uses for DOM work (design.md D6).
11	 *
12	 * All decision logic is pure (classify.ts, escalate.ts, enforce.ts); this
13	 * module only extracts facts from a `Transaction`, converts between CM6
14	 * character offsets and line/ch positions, and applies the verdict.
15	 */
16	
17	import {
18	  EditorSelection,
19	  EditorState,
20	  StateEffect,
21	  Transaction,
22	  type ChangeSpec,
23	  type Extension,
24	  type SelectionRange,
25	  type Text,
26	  type TransactionSpec,
27	} from '@codemirror/state';
28	import { EditorView } from '@codemirror/view';
29	import { editorInfoField, Notice } from 'obsidian';
30	import type { OutlineDoc } from '../model';
31	import { encodeLines } from '../encode';
32	import { classify, type ChangedLineSpan, type TransactionFacts } from '../classify';
33	import { clampCursorToContent, escalateRanges, rangesEqual, type LinePos, type LineRange } from '../escalate';
34	import { computeVerdict, type EditFact, type RewriteVerdict } from '../enforce';
35	import type { Edit, RejectionReason } from '../result';
36	import { applyEdits } from '../result';
37	import { editsToChanges } from './dispatch';
38	import { REJECTION_MESSAGES } from './messages';
39	import type { ModeSource } from './keymap';
40	import { parsedDoc } from './parsed-doc';
41	import type { TransactionStats } from './stats';
42	
43	export interface ClassificationSource extends ModeSource {
44	  readonly debugCrossCheck: boolean;
45	}
46	
47	/** Carries a veto's rejection reason to the update listener (design.md D6):
48	 * the filter attaches it, never shows the cue itself. */
49	export const vetoEffect = StateEffect.define<RejectionReason>();
50	
51	function offsetToLinePos(doc: Text, pos: number): LinePos {
52	  const line = doc.lineAt(pos);
53	  return { line: line.number - 1, ch: pos - line.from };
54	}
55	
56	function linePosToOffset(doc: Text, pos: LinePos): number {
57	  return doc.line(pos.line + 1).from + pos.ch;
58	}
59	
60	/** Old-document (`tr.startState.doc`) line spans touched by this
61	 * transaction's changes — inclusive on both ends (classify.ts's
62	 * convention). A pure insertion (fromA === toA) only ever touches the one
63	 * line it lands on. Also carries the two Phase C facts classify.ts needs to
64	 * recognize boundary shapes a line-only span can't (node-edit-enforcement
65	 * D4/D5): the inserted text itself, and whether this change deletes
66	 * exactly one line-break character. */
67	function collectChangedLineSpans(tr: Transaction): ChangedLineSpan[] {
68	  const spans: ChangedLineSpan[] = [];
69	  tr.changes.iterChangedRanges((fromA, toA, fromB, toB) => {
70	    const fromLineObj = tr.startState.doc.lineAt(fromA);
71	    const toLineObj = tr.startState.doc.lineAt(Math.max(fromA, toA - 1));
72	    const insertedText = tr.newDoc.sliceString(fromB, toB);
73	    const deletesLineBoundary = toA === fromA + 1 && fromLineObj.to === fromA;
74	    spans.push({
75	      fromLine: fromLineObj.number - 1,
76	      toLine: toLineObj.number - 1,
77	      insertedText,
78	      deletesLineBoundary,
79	      fromCh: fromA - fromLineObj.from,
80	      toCh: toA - toLineObj.from,
81	    });
82	  });
83	  return spans;
84	}
85	
