88	 * for the verdict layer (`EditFact`). `undefined` when the transaction has
89	 * zero or more-than-one change ranges — the verdict layer treats that as
90	 * `pass` (design.md D1's conservative bias: this phase models the
91	 * single-range shapes the spec scenarios describe, not multi-cursor edits).
92	 */
93	function collectEditFact(tr: Transaction): EditFact | undefined {
94	  let fact: EditFact | undefined;
95	  let count = 0;
96	  const cursorBefore = offsetToLinePos(tr.startState.doc, tr.startState.selection.main.head);
97	  tr.changes.iterChangedRanges((fromA, toA, fromB, toB) => {
98	    count++;
99	    if (count > 1) return;
100	    fact = {
101	      from: offsetToLinePos(tr.startState.doc, fromA),
102	      to: offsetToLinePos(tr.startState.doc, toA),
103	      insert: tr.newDoc.sliceString(fromB, toB),
104	      cursorBefore,
105	    };
106	  });
107	  return count === 1 ? fact : undefined;
108	}
109	
110	/** `verdict.edits` (old-document line ranges) → a CM6 `ChangeSpec` against
111	 * `tr.startState.doc`, via the same `editsToChanges` position-based
112	 * conversion the grammar's own dispatches use. */
113	function editsToChangeSpec(doc: Text, oldLines: readonly string[], edits: readonly Edit[]): ChangeSpec[] {
114	  return editsToChanges(oldLines, edits).map((c) => ({
115	    from: linePosToOffset(doc, c.from),
116	    to: linePosToOffset(doc, c.to),
117	    insert: c.text,
118	  }));
119	}
120	
121	/** Character offset of a `{line, ch}` position in a freshly-built lines
122	 * array (the NEW document a rewrite's edits produce) — no `Text` instance
123	 * needed, mirroring grammar.ts's own `offsetInNewText`. */
124	function offsetInLines(lines: readonly string[], pos: { line: number; ch: number }): number {
125	  let offset = 0;
126	  for (let i = 0; i < pos.line && i < lines.length; i++) offset += (lines[i] ?? '').length + 1;
127	  return offset + pos.ch;
128	}
129	
130	function toLineRange(doc: Text, range: SelectionRange): LineRange {
131	  return { anchor: offsetToLinePos(doc, range.anchor), head: offsetToLinePos(doc, range.head) };
132	}
133	
134	/**
135	 * Escalates the transaction's resulting selection (`tr.newSelection` — the
136	 * old selection unchanged for a selection-only transaction with no explicit
137	 * new selection, or the dispatched new selection otherwise) through the
138	 * pure `escalateRanges`, which applies both the per-range rules and the
139	 * uniform multi-range rule (D4 as amended). A cursor (empty range) that
140	 * `escalateRanges` leaves untouched by design is additionally run through
141	 * `clampCursorToContent` (D13) — a separate, narrower mechanism for list-
142	 * item marker prefixes only. Returns `undefined` if no range actually
143	 * changed, so the caller can skip wrapping the transaction.
144	 */
145	function escalateSelection(
146	  outlineDoc: OutlineDoc,
147	  doc: Text,
148	  tr: Transaction,
149	): EditorSelection | undefined {
150	  const before = tr.newSelection.ranges.map((range) => toLineRange(doc, range));
151	  const escalated = escalateRanges(outlineDoc, before);
152	  const after = escalated.map((range) => {
153	    if (range.anchor.line !== range.head.line || range.anchor.ch !== range.head.ch) return range;
154	    const clamped = clampCursorToContent(outlineDoc, range.anchor);
155	    return clamped === range.anchor ? range : { anchor: clamped, head: clamped };
156	  });
157	  let changed = false;
158	  const ranges = tr.newSelection.ranges.map((original, i) => {
159	    if (rangesEqual(before[i]!, after[i]!)) return original;
160	    changed = true;
161	    const anchor = linePosToOffset(doc, after[i]!.anchor);
162	    const head = linePosToOffset(doc, after[i]!.head);
163	    return EditorSelection.range(anchor, head);
164	  });
165	  if (!changed) return undefined;
166	  return EditorSelection.create(ranges, tr.newSelection.mainIndex);
167	}
168	
169	/**
170	 * Builds the replacement `TransactionSpec` for a `rewrite` verdict
171	 * (design.md D7): the original changes are replaced WHOLESALE (never
172	 * layered on top of `tr` — that would apply both), carrying the verdict's
173	 * plugin-own `userEvent` (the D7a short-circuit), the post-op cursor as an
174	 * explicit selection, and an explicit `addToHistory: true` so the rewrite
175	 * forms exactly one undo step.
176	 */
