178	  const oldLines = encodeLines(outlineDoc);
179	  const changes = editsToChangeSpec(tr.startState.doc, oldLines, verdict.edits);
180	  const newLines = applyEdits(oldLines, verdict.edits);
181	  const cursorOffset = offsetInLines(newLines, verdict.cursor);
182	  return {
183	    changes,
184	    selection: EditorSelection.cursor(cursorOffset),
185	    userEvent: verdict.userEvent,
186	    annotations: Transaction.addToHistory.of(true),
187	  };
188	}
189	
190	export function transactionFilterExtension(
191	  source: ClassificationSource,
192	  stats: TransactionStats,
193	): Extension {
194	  const filter = EditorState.transactionFilter.of((tr) => {
195	    const path = tr.startState.field(editorInfoField, false)?.file?.path;
196	    if (!path || !source.isOutline(path)) return tr; // off-mode: byte-for-byte stock, nothing recorded
197	
198	    const start = performance.now();
199	    const userEvent = tr.annotation(Transaction.userEvent);
200	    const isComposition = tr.isUserEvent('input.type.compose');
201	    const changedLineSpans = collectChangedLineSpans(tr);
202	    const { doc: outlineDoc } = parsedDoc(tr.startState.doc);
203	
204	    const cursorBefore = offsetToLinePos(
205	      tr.startState.doc,
206	      tr.startState.selection.main.head,
207	    );
208	    const facts: TransactionFacts = { userEvent, isComposition, changedLineSpans, cursorBefore };
209	    const cls = classify(facts, outlineDoc);
210	
211	    let result: Transaction | TransactionSpec | readonly [Transaction, { selection: EditorSelection }] = tr;
212	    let verdictKind: 'pass' | 'rewrite' | 'veto' | undefined;
213	
214	    if (cls === 'selection-only') {
215	      const escalated = escalateSelection(outlineDoc, tr.startState.doc, tr);
216	      if (escalated) result = [tr, { selection: escalated }];
217	    } else if (cls === 'boundary-crossing-edit') {
