219	      const verdict = computeVerdict(cls, outlineDoc, edit);
220	      verdictKind = verdict.kind;
221	      if (verdict.kind === 'rewrite') {
222	        result = buildRewriteSpec(tr, outlineDoc, verdict);
223	      } else if (verdict.kind === 'veto') {
224	        // Dissolve the transaction: no changes, no selection change — just
225	        // an effect the update listener below observes to show the cue
226	        // (design.md D6: never a side effect inside the filter itself).
227	        result = { effects: vetoEffect.of(verdict.reason) };
228	      }
229	    }
