import { createNote } from '../helpers';

describe('probe: indentUnit facet vs useTab setting', () => {
  it('reports facet value under both settings', async () => {
    await createNote('probe.md', '- a\n- b\n');

    const probe = () =>
      browser.executeObsidian(async ({ app, obsidian }) => {
        const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
        if (!view) throw new Error('no view');
        // @ts-expect-error private-ish internals, probe-only, not shipped
        const cm = view.editor.cm;
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        const { indentUnit, getIndentUnit } = require('@codemirror/language');
        const unit = cm.state.facet(indentUnit);
        const width = getIndentUnit(cm.state);
        const useTab = app.vault.getConfig('useTab');
        const tabSize = app.vault.getConfig('tabSize');
        return { unit, width, useTab, tabSize };
      });

    const before = await probe();
    console.log('BEFORE', JSON.stringify(before));

    await browser.executeObsidian(async ({ app }) => {
      // @ts-expect-error private-ish, probe-only
      app.vault.setConfig('useTab', !app.vault.getConfig('useTab'));
      app.workspace.updateOptions();
    });

    const after = await probe();
    console.log('AFTER', JSON.stringify(after));

    expect(before.unit).not.toBe(after.unit);
  });
});

