371	  const parentPath = path.slice(0, -1);
372	  const index = path[path.length - 1]!;
373	  const parent = nodeAt(doc, parentPath)!;
374	
375	  if (parent.kind === 'heading') {
376	    // Heading scope is positional: content placed after a section's body is
377	    // still inside the section — there is no "sibling of my heading" spot.
378	    return reject('not-expressible-under-target');
379	  }
380	
381	  const grandPath = parentPath.slice(0, -1);
382	  const parentIndex = parentPath[parentPath.length - 1]!;
383	  const grandParent = grandPath.length === 0 ? undefined : nodeAt(doc, grandPath)!;
384	  if (grandPath.length > 0 && grandParent!.kind === 'heading' && node.kind !== 'paragraph' && node.kind !== 'list-item' && !isAtom(node)) {
385	    return reject('not-expressible-under-target');
386	  }
387	  const grandSiblings = childrenAt(doc, grandPath);
388	
389	  const newKind = isContent(node)
390	    ? encodingKindAtDestination({
391	        parentKind: grandParent ? grandParent.kind : 'root',
392	        precedingSiblings: grandSiblings.slice(0, parentIndex + 1),
393	        followingSiblings: grandSiblings.slice(parentIndex + 1),
394	      })
