344	function deleteAndSplice(doc: OutlineDoc, ids: readonly number[], parsedBlocks: readonly OutlineNode[]): Verdict {
345	  const deletion = deleteSubtrees(doc, ids);
346	  if (!deletion.ok) return vetoFrom(deletion);
347	
348	  if (parsedBlocks.length === 0) {
349	    return rewriteFrom(deletion.value, 'delete.structural');
350	  }
351	
352	  const { parentPath, before, after } = survivorsOf(doc, ids);
353	  const doc2 = deletion.value.doc;
354	  // `before`/`after` carry ids from the PRE-deletion `doc` — `deleteSubtrees`
355	  // (like every op) returns a tree from a FRESH `finalize` reparse, which
356	  // assigns all-new ids. The survivor's identity only survives the crossing
357	  // as a LINE position: `deletion.value.cursor` was placed exactly on it.
358	  const survivorInDoc2 = before || after ? nodeAtLine(doc2, deletion.value.cursor.line) : undefined;
359	
360	  let inserted: OpResult<OpOutput>;
361	  if (after && survivorInDoc2) {
362	    inserted = insertSubtrees(doc2, survivorInDoc2.id, parsedBlocks, 'before');
363	  } else if (before && survivorInDoc2) {
364	    inserted = insertSubtrees(doc2, survivorInDoc2.id, parsedBlocks, 'after');
365	  } else {
366	    inserted = insertAsOnlyChildren(doc2, parentPath, parsedBlocks);
367	  }
368	  if (!inserted.ok) return vetoFrom(inserted);
369	
370	  const finalText = encode(inserted.value.doc);
371	  const finalLines = finalText === '' ? [] : finalText.split('\n');
372	  const finalEdits = diffLines(encodeLines(doc), finalLines);
373	  const cursor = endOfInsertedRun(inserted.value.doc, inserted.value.cursor, parsedBlocks.length);
374	  return { kind: 'rewrite', edits: finalEdits, cursor, userEvent: 'input.paste.structural' };
375	}
