381	/** A list item with no content of its own (just typed, e.g. via Enter) and
382	 * no children — the paste-anchor case where the anchor should be REPLACED
383	 * by the pasted content rather than left stranded next to it. */
384	function isEmptyAnchor(node: OutlineNode): boolean {
385	  if (node.kind !== 'list-item' || node.children.length > 0 || node.lines.length !== 1) return false;
386	  const line = node.lines[0]!;
387	  return line.slice(contentColumnCh(line)).trim() === '';
388	}
