390	function computeDeletionVerdict(doc: OutlineDoc, edit: EditFact): Verdict {
391	  const range: LineRange = { anchor: edit.from, head: edit.to };
392	  const ids = coverIdsOf(doc, range);
393	  if (!ids) return PASS; // preamble jurisdiction
394	
395	  if (edit.insert === '') {
396	    const deletion = deleteSubtrees(doc, ids);
397	    if (!deletion.ok) return vetoFrom(deletion);
398	    return rewriteFrom(deletion.value, 'delete.structural');
399	  }
400	  return composeTypeOver(doc, ids, edit.insert);
401	}
402	
403	/**
404	 * Structural-paste rule (design.md D5, corrected D15): a pure insertion
405	 * whose text parses as a structural block sequence (`isStructuralBlockSequence`
406	 * — more than one top-level block, OR a single top-level node that itself
407	 * has children), landing inside a node, splices at the nearest boundary
408	 * AFTER that node — UNLESS that node is an empty placeholder (a freshly-
409	 * split/created list item with no content and no children, D14), in which
410	 * case the paste REPLACES it rather than leaving it stranded next to the
411	 * pasted content. Conservative on failure: an inexpressible sequence (or
412	 * ambiguous shape) stays native rather than surprising the user with a
413	 * veto — "a wrong pass is editable text; a wrong rewrite is surprising
414	 * relocation."
415	 */
416	function computePasteVerdict(doc: OutlineDoc, edit: EditFact): Verdict {
417	  const node = nodeAtLine(doc, edit.from.line);
418	  if (!node) return PASS;
419	  const parsedBlocks = parse(edit.insert).children;
420	  if (!isStructuralBlockSequence(parsedBlocks)) return PASS;
421	
422	  if (isEmptyAnchor(node)) {
423	    const verdict = deleteAndSplice(doc, [node.id], parsedBlocks);
424	    if (verdict.kind === 'rewrite') return verdict;
425	    // Fall through to the plain splice-after path below if replacing the
426	    // empty anchor didn't work out for some reason (conservative bias).
427	  }
428	
429	  const inserted = insertSubtrees(doc, node.id, parsedBlocks, 'after');
430	  if (!inserted.ok) return PASS;
431	  const cursor = endOfInsertedRun(inserted.value.doc, inserted.value.cursor, parsedBlocks.length);
432	  return { kind: 'rewrite', edits: inserted.value.edits, cursor, userEvent: 'input.paste.structural' };
433	}
434	
435	/** The verdict for one transaction. `edit` is `undefined` for shapes this
436	 * phase doesn't model (multi-range changes) — always `pass`, never a veto,
437	 * per the conservative-default-permit posture (D1). */
438	export function computeVerdict(
439	  cls: TransactionClass,
440	  doc: OutlineDoc,
441	  edit: EditFact | undefined,
442	): Verdict {
443	  if (cls !== 'boundary-crossing-edit' || !edit) return PASS;
444	
445	  const isPureInsertion = edit.from.line === edit.to.line && edit.from.ch === edit.to.ch;
446	  if (isPureInsertion) {
447	    return edit.insert === '' ? PASS : computePasteVerdict(doc, edit);
448	  }
449	  // Merge shapes route first (D10): single-newline and marker-space
450	  // deletions are either merge intents, native chrome edits, or the
451	  // first-node veto — never subtree-cover deletions. Everything else falls
452	  // through to the deletion path.
453	  const intent = recognizeMergeIntent(doc, edit);
454	  if (intent === 'native') return PASS;
455	  if (intent !== undefined) return computeMergeVerdict(doc, intent);
456	  return computeDeletionVerdict(doc, edit);
457	}
