1	/**
2	 * Keyboard grammar with real key events — automates the "Keyboard grammar"
3	 * checklist of openspec/changes/editor-core/verification.md. Structure-level
4	 * assertions reuse the plugin's own pure parser on the buffer text.
5	 */
6	
7	import { expect } from '@wdio/globals';
8	import { obsidianPage } from 'wdio-obsidian-service';
9	import * as h from '../helpers.js';
10	import { REJECTION_MESSAGES } from '../../src/plugin/messages';
11	import { parse } from '../../src/parse';
12	import { walkNodes } from '../../src/model';
13	
14	const NOTE = 'Scratch/grammar.md';
15	
16	/** Scratch note with outline mode ON, buffer + cursor arranged. */
17	async function grammarNote(content: string, line: number, ch: number): Promise<void> {
18	  await h.createNote(NOTE, content);
19	  if (!(await h.isOutlineMode(NOTE))) {
20	    await h.toggleOutlineMode();
21	    await h.waitForNotice('Outline mode on');
22	    await h.dismissNotices();
23	  }
24	  await h.setCursor(line, ch);
25	}
26	
27	async function modeOff(): Promise<void> {
28	  if (await h.isOutlineMode(NOTE)) {
29	    await h.toggleOutlineMode();
30	    await h.waitForNotice('Outline mode off');
31	    await h.dismissNotices();
32	  }
33	}
34	
35	describe('keyboard grammar', function () {
36	  before(async function () {
37	    await obsidianPage.resetVault();
38	    await h.resetPluginState();
39	  });
40	
41	  afterEach(async function () {
42	    await h.dismissNotices();
43	  });
44	
45	  it('off-mode: keys behave stock — no grammar transforms, no notices', async function () {
46	    await h.createNote(NOTE, 'Only.\n');
47	    await modeOff();
48	    await h.setCursor(0, 5);
49	
50	    // In outline mode this exact position rejects Tab with a notice and no
51	    // change; stock behavior inserts whitespace silently.
52	    await h.keys.tab();
53	    const after = await h.getBuffer();
54	    // Stock behavior inserts whitespace somewhere (exact placement is
55	    // Obsidian's business); grammar would have rejected with a cue instead.
56	    expect(after).not.toBe('Only.\n');
57	    expect(after).toContain('Only.');
58	    expect(await h.noticeTexts()).toEqual([]);
59	  });
60	
61	  it('toggling mode applies to the very next keypress', async function () {
62	    await grammarNote('Only.\n', 0, 5);
63	
64	    await h.keys.tab(); // grammar: nothing above to indent under → cue, inert
65	    await h.waitForNotice(REJECTION_MESSAGES['no-previous-sibling']);
66	    expect(await h.getBuffer()).toBe('Only.\n');
67	    await h.dismissNotices();
68	
69	    await h.toggleOutlineMode(); // off
70	    await h.waitForNotice('Outline mode off');
71	    await h.dismissNotices();
72	    await h.setCursor(0, 5);
73	    await h.keys.tab(); // stock: inserts whitespace
74	    expect(await h.getBuffer()).not.toBe('Only.\n');
75	
76	    await h.toggleOutlineMode(); // on again
77	    await h.waitForNotice('Outline mode on');
78	    await h.dismissNotices();
79	    await h.setBuffer('Only.\n');
80	    await h.setCursor(0, 5);
81	    await h.keys.tab(); // grammar governs the very next keypress
82	    await h.waitForNotice(REJECTION_MESSAGES['no-previous-sibling']);
83	    expect(await h.getBuffer()).toBe('Only.\n');
84	  });
85	
86	  it('Tab/Shift+Tab indent and outdent the node at the cursor', async function () {
87	    await grammarNote('- alpha\n- beta\n', 1, 4);
88	
89	    await h.keys.tab();
90	    const indented = await h.getBuffer();
91	    // beta is now a child of alpha (indentation string is vault-dependent).
92	    const nodes = [...walkNodes(parse(indented))];
93	    expect(nodes.length).toBe(2);
94	    const alpha = parse(indented).children[0]!;
95	    expect(alpha.children.length).toBe(1);
96	    expect(alpha.children[0]!.lines[0]!.trim()).toBe('- beta');
97	    // Cursor sits at content start of the moved node.
98	    const cursor = await h.getCursor();
99	    const betaLine = indented.split('\n')[1]!;
100	    expect(cursor.line).toBe(1);
101	    expect(betaLine.slice(cursor.ch)).toBe('beta');
102	
103	    await h.keys.shiftTab();
104	    expect(await h.getBuffer()).toBe('- alpha\n- beta\n');
105	  });
106	
107	  it('Alt+Up/Down move nodes with their children; ordered runs renumber', async function () {
108	    await grammarNote('- a\n\t- a1\n- b\n', 0, 2);
109	    await h.keys.altDown();
