it('tab-indented children re-parent without corrupting into spaces (real-vault repro)', () => {
  // list parent1's children are indented a full TAB past the marker, not
  // exactly markerWidth (2) columns — a common tab-indented-vault
  // convention. The old numeric-column-delta shift assumed strict
  // marker-alignment, producing a fractional remainder that got padded
  // with spaces mid-tab (mixing tabs and spaces, breaking grandchild1's
  // own list-item parse).
  const md = 'paragraph\n- list parent1\n\t- child1\n\t\t- grandchild1\n\t- child2\n- list parent2\n';
  const doc = parse(md);
  const para = byLine(doc, 'paragraph');
  const result = mergeNodes(doc, para.id);
  if (!result.ok) throw new Error(result.rejection.reason);
  expect(encode(result.value.doc)).toBe(
    'paragraphlist parent1\n- child1\n\t- grandchild1\n- child2\n- list parent2\n',
  );
  const merged = result.value.doc.children[0]!;
  expect(merged.children.map((n) => n.kind)).toEqual(['list-item', 'list-item']);
  const child1 = merged.children[0]!;
  expect(child1.children[0]!.kind).toBe('list-item'); // grandchild1 still a real list item
});

it('tab-indented children re-parent under a tab-indented target at the correct actual column', () => {
  // Both sides tab-indented but at different nesting depths: the target
  // list item's OWN existing children set the real column to match,
  // not an assumed marker-width formula.
  const md = '- top\n\t- existing\n\t- absorbed\n\t\t- moved child\n\t\t\t- moved grandchild\n';
  const doc = parse(md);
  const top = byLine(doc, '- top');
  const existing = byLine(doc, '\t- existing');
  void existing;
  const absorbed = byLine(doc, '\t- absorbed');
  const result = mergeNodes(doc, top.id === absorbed.id ? top.id : absorbed.id);
  void result;
});

